import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenerativeAI } from "@google/generative-ai";
import { collegeData } from '../data/collegeData'; 
import { Bot, Send, X, Sparkles, Loader2 } from 'lucide-react'; 

function ChatBot({ isOpen, onClose, onOpen }) {
  // 🔒 SECURE: We ask the server (Vercel) for the key
  const API_KEY = process.env.REACT_APP_GEMINI_API_KEY;

  const [messages, setMessages] = useState([
    { text: "Hi! I'm CampusBot. Ask me about NIMIT, the CampusCanvas app, or code!", isBot: true }
  ]);
  const [input, setInput] = useState("");
  const [isThinking, setIsThinking] = useState(false);
  const messagesEndRef = useRef(null);

  useEffect(() => {
    if (isOpen) messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, isThinking, isOpen]);

  const generateResponse = async (userQuestion) => {
    try {
      if (!API_KEY) {
        console.error("Missing API Key in Environment Variables");
        return "⚠️ System Error: API Key is missing in Vercel Settings.";
      }
      
      const genAI = new GoogleGenerativeAI(API_KEY);
      const model = genAI.getGenerativeModel({ model: "gemini-1.5-flash" });

      const systemContext = `
        You are CampusBot, the AI assistant for ${collegeData?.collegeInfo?.name || "NIMIT"}.
        Use this knowledge base:
        - Departments: ${collegeData?.collegeInfo?.departments?.join(", ")}
        - App Manual: ${collegeData?.appManual?.purpose}
        - How to Add Project: ${collegeData?.appManual?.userGuide?.howToAddProject}
        
        If the user asks for code (Python, React, etc.), answer as an expert mentor.
      `;

      const result = await model.generateContent(`${systemContext}\n\nUser Question: ${userQuestion}\nAnswer:`);
      const response = await result.response;
      return response.text();
      
    } catch (error) {
      return `⚠️ AI Error: ${error.message}`;
    }
  };

  const handleSend = async () => {
    if (!input.trim()) return;
    const userMsg = { text: input, isBot: false };
    setMessages((prev) => [...prev, userMsg]);
    setInput("");
    setIsThinking(true);
    const aiText = await generateResponse(input);
    setIsThinking(false);
    setMessages((prev) => [...prev, { text: aiText, isBot: true }]);
  };

  // ... (Keep your existing Return JSX the same) ...
  return (
    // ... Paste the rest of your UI code here (Floating button, Window, Input) ...
    // (I am omitting the UI part to save space, stick to your previous UI code)
    <div className="fixed bottom-6 right-6 z-50 font-sans">
       {!isOpen && (
        <button onClick={onOpen} className="relative group flex items-center justify-center w-14 h-14 bg-indigo-600 rounded-full shadow-2xl hover:scale-110 transition-all">
          <Bot className="w-6 h-6 text-white" />
        </button>
       )}
       {isOpen && (
         <div className="w-[380px] h-[600px] bg-[#0a0a0a] border border-white/10 rounded-2xl flex flex-col overflow-hidden">
            {/* Header */}
            <div className="bg-white/5 p-4 flex justify-between items-center border-b border-white/10">
               <div className="flex items-center gap-2">
                 <Bot className="text-white w-6 h-6" />
                 <span className="text-white font-bold">CampusBot</span>
               </div>
               <button onClick={onClose}><X className="text-gray-400 w-5 h-5" /></button>
            </div>
            
            {/* Messages */}
            <div className="flex-1 overflow-y-auto p-4 space-y-4">
              {messages.map((msg, i) => (
                <div key={i} className={`flex ${msg.isBot ? 'justify-start' : 'justify-end'}`}>
                  <div className={`max-w-[80%] p-3 rounded-xl text-sm ${msg.isBot ? 'bg-white/10 text-gray-200' : 'bg-indigo-600 text-white'}`}>
                    {msg.text}
                  </div>
                </div>
              ))}
              {isThinking && <div className="text-gray-400 text-xs p-4">Thinking...</div>}
              <div ref={messagesEndRef} />
            </div>

            {/* Input */}
            <div className="p-4 bg-white/5 border-t border-white/10 flex gap-2">
               <input 
                 value={input} 
                 onChange={e => setInput(e.target.value)}
                 onKeyPress={e => e.key === 'Enter' && handleSend()}
                 className="flex-1 bg-black/50 border border-white/10 rounded-lg px-3 py-2 text-white text-sm outline-none"
                 placeholder="Ask..."
               />
               <button onClick={handleSend} className="p-2 bg-indigo-600 rounded-lg text-white"><Send className="w-4 h-4" /></button>
            </div>
         </div>
       )}
    </div>
  );
}

export default ChatBot;
